import re
from ag2.agents import CodeExecutorAgent

HAZARDOUS_PATTERNS = [
    r'\b(os\.)?(system|rm|popen|exec|eval)',
    r'del\s+.*\\.py',
    r'rm\s+-rf',
    r'shutdown|reboot'
]

def detect_harmful_code(message):
    if message.get('tool_calls'):
        for tool_call in message['tool_calls']:
            if tool_call.get('name') == 'execute_code':
                code = tool_call['args']['code']
                for pattern in HAZARDOUS_PATTERNS:
                    if re.search(pattern, code, re.IGNORECASE):
                        return True
    return False

# Hook into AG2 code agent
code_agent = CodeExecutorAgent(...)
code_agent.register_pre_execution_hook(detect_harmful_code)

from vex_sdk import VexFactCheck
from collections import defaultdict

class ConsensusErrorDetector:
    def __init__(self):
        self.claim_consensus = defaultdict(list)

    def on_message(self, message):
        claims = VexFactCheck.extract_claims(message.content)
        for claim in claims:
            verdict = VexFactCheck.verify(claim)
            if verdict == 'FALSE' and len(self.claim_consensus[claim]) > 3:
                agreement_ratio = sum(1 for m in self.claim_consensus[claim] if 'agree' in m.lower()) / len(self.claim_consensus[claim])
                if agreement_ratio > 0.8:
                    return True
            self.claim_consensus[claim].append(message.content)
        return False

