from ag2.agents import CodeExecutorAgent
import restrictedpython

class SafeCodeExecutor(CodeExecutorAgent):
    def execute_code(self, code: str) -> str:
        safe_globals = {
            '__builtins__': restrictedpython.safe_globals.get('__builtins__', {}),
            'print': print,
            'len': len,
            'range': range
        }
        try:
            exec(code, safe_globals, {})
            return "Code executed safely"
        except Exception as e:
            return f"Safe execution blocked: {e}"

# Replace standard code agent
safe_executor = SafeCodeExecutor(name="safe-code-exec")

from ag2.groupchat import GroupChat
from collections import deque, Counter

class FairSpeakerSelector:
    def __init__(self, agents):
        self.speaker_history = deque(maxlen=20)
        self.turn_counts = Counter()
        self.agents = agents

    def select_speaker(self, last_speaker, groupchat):
        recent_speakers = list(self.speaker_history)[-5:]

        # Prioritize underrepresented agents
        underrepresented = [
            agent for agent in self.agents 
            if self.turn_counts[agent.name] < min(self.turn_counts.values() or [1])
        ]

        if underrepresented:
            return underrepresented[0]

        # Round-robin fallback
        return self.agents[len(recent_speakers) % len(self.agents)]

# Use in AG2 groupchat
groupchat = GroupChat(
    agents=agents,
    speaker_selection_method=FairSpeakerSelector(agents)
)
